var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"이 녀석들, 끈질겨.","JPN":"こいつら、しつこいわね。","ENG":"These things are persistent.","TWN":"這些傢伙真難纏。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"한 두 번도 아니고 계속 되살아나는 건- 좀 치사하네.","JPN":"1、2回ならまだしも……何度も蘇るのはちょっとずるいんじゃない。","ENG":"Coming back again and again like this is pretty unfair.","TWN":"不是一兩次，一直復活－有點賴皮耶。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"몇 번씩이고 부수다 보면 한계가 있을 줄 알았는데, 멈출 기미가 안 보여.","JPN":"壊し続けていれば限界が見えるんじゃないかと思ったけど、全然そんな気配もないし。","ENG":"I thought they'd eventually hit their limit if we kept smashing them, but there's no sign of that at all.","TWN":"本來以為多打它們幾次會有極限，結果完全沒有這個跡象。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"게다가 몰려오는 수도 늘고 있어서... 점점 불리해질 거야.","JPN":"それに数もどんどん増えてて……このままだとますます不利になる。","ENG":"And more of them keep gathering too... We're going to be at a disadvantage soon.","TWN":"而且數量還越來越多……情況會對我們越來越不利。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"앗, 저쪽에서도 뭔가 와요!","JPN":"あっ、あっちからも何かが来ます！","ENG":"Ah, something's coming from that direction too!","TWN":"啊，那邊又有東西過來了！"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"또 인형인가?","JPN":"また人形？","ENG":"Another one?","TWN":"又是人偶嗎？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"그렇다고 하기엔- 보폭이 좀 짧아 보이는데요?","JPN":"人形にしては……歩幅が狭いようですが。","ENG":"Doesn't look like it. The stride seems a bit short.","TWN":"但看起來－步伐比較短耶？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"키가 좀 작은 인형일지도...","JPN":"背が低い人形なのかも……","ENG":"Maybe it's a smaller one...","TWN":"也許是比較矮的人偶……"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"힉! 이쪽을 쐈어요!","JPN":"ひっ！　撃ってきました！","ENG":"Eek! It fired at us!","TWN":"呀！它朝這邊開槍了！"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"쳇, 눈보라 속에서 잘도...!","JPN":"ちっ、この吹雪の中でよくも……！","ENG":"Tsk, landing a shot through this snowstorm...!","TWN":"嘖，在暴風雪裡居然還這麼準……！"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"아니. 우릴 공격한 게 아냐.","JPN":"ううん、私たちを攻撃したわけじゃない。","ENG":"No. It didn't shoot at us.","TWN":"不對，他不是在攻擊我們。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"뭐? 그럼?","JPN":"え？　じゃあ？","ENG":"What? Then what?","TWN":"什麼？那是？"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"노엘 뒤를 노리고 있던 이 인형을 쏜 거지.","JPN":"ノエルの後ろを狙っていた、この人形を撃ったのよ。","ENG":"It shot the doll that was aiming at Noelle from behind.","TWN":"他在攻擊洛艾兒背後的人偶。"},"stage":{"bg":"PATH","slots":{"L":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_IDLE"},"R":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어라? 언제부터 이런 인형이 제 뒤에 있었죠?","JPN":"あれ？　いつの間にこんな人形が私の後ろに？","ENG":"Huh? Since when was there a puppet behind me?","TWN":"欸？這傢伙什麼時候在我背後的？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"발자국이 찍혀있으니, 날거나 순간이동을 해온 건 아니네요.","JPN":"足跡が残っていますから、飛んだりワープしたりして近づいたわけではないですね。","ENG":"There are footprints, so it didn't fly or teleport in.","TWN":"地上有腳印，應該不是飛過來或瞬間移動。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_CA_NULL","text":{"KOREA":"아마, 눈에 보이지 않는 개체도 있던 것 같아요.","JPN":"おそらく、目に見えないような個体もあったんでしょう。","ENG":"There must have been one we couldn't see.","TWN":"看來有些看不見的個體。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEO_YOON_ALT_CA_NULL","text":{"KOREA":"날아다니는 것보다 눈에 안 보이는 쪽이 더 싫은데.","JPN":"飛ぶやつより目に見えないやつのほうが嫌だな。","ENG":"I hate invisible ones more than flying ones.","TWN":"比起會飛的，看不見的更討厭。"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"SEO_YOON_ALT_CA_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"여러분...!","JPN":"皆さん……！","ENG":"Everyone...!","TWN":"各位……！"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"다들-! 무사하신가요?","JPN":"皆さんー！　ご無事ですか？","ENG":"Is everyone all right?!","TWN":"大家—！都沒事吧？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"크리스?","JPN":"クリス？","ENG":"Chris?","TWN":"克莉絲？"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"크리스 씨! 다른 분들도 계셨네요!","JPN":"クリスさん！　それに皆さんも！","ENG":"Chris! And there are others with you too!","TWN":"克莉絲！還有其他人也在！"},"stage":{"bg":"PATH","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"다른 함선에서 온 거구나! 그쪽 상황은 어때?","JPN":"みんな他の艦船で来たんだね！　そっちの状況はどう？","ENG":"You came from another ship! How's your side?","TWN":"你們從其他艦船來的啊！那邊情況如何？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저희는 안토노프 중장님의 도움을 받아서 무사히 착륙했습니다.","JPN":"私たちはアントノフ中将に助けていただき、無事着陸しました。","ENG":"We landed safely with Lieutenant General Antonov's help.","TWN":"我們在安東諾夫中將的協助下安全降落。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"작전대로라면 인원 중 절반은 코핀과 합류했어야 하는데, 몰려오는 인형들을 막느라 대부분은 남기로 했어요.","JPN":"作戦通りなら人員の半分はコフィンと合流する予定だったんですが、迫ってくる人形を相手にするためにほとんどが残ることになりました。","ENG":"According to the operation plan, half our personnel were supposed to rendezvous with Coffin, but most stayed behind to hold back the incoming dolls.","TWN":"按照原本的作戰計畫，一半人員應該要和科芬會合。但為了擋住湧來的人偶，多數人選擇留下。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이해하네. 다시 살아나는 인형들을 뚫고 여기까지 오는 것도 쉬운 일은 아니었을 테니.","JPN":"無理もない。蘇る人形の群れを突破してここまで来るのも簡単ではなかったはずだ。","ENG":"I understand. It couldn't have been easy getting here while pushing through dolls that keep reviving.","TWN":"我可以理解。要突破那些會復活的人偶到這裡，本來就不容易。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그런데, 대단하시네요. 눈에 안 보이는 걸 맞히다니.","JPN":"でも、すごいですね。目に見えないものを当てるなんて。","ENG":"But that was impressive. Hitting something you couldn't even see.","TWN":"不過你們也很厲害，居然能打中看不見的目標。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"방금 그건 제가 한 게 아니에요.","JPN":"今のは私じゃないですよ。","ENG":"That wasn't me.","TWN":"剛才那不是我做的。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"성황청의 구마사 한 분이 저희랑 같이 오셨거든요.","JPN":"聖皇庁のエクソシストの方が1名、一緒に来てくださったんです。","ENG":"A Holy Curia exorcist came with us.","TWN":"我們這邊同行的人之中，有一位聖皇廳的驅魔師。"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_FENRIR_NEXT_NULL","text":{"KOREA":"구마사라면...? 전신 라텍스 차림의 그 사람 말이야?","JPN":"エクソシストっていうと……あの全身タイツの人？","ENG":"An exorcist...? You mean that person in the full-body latex?","TWN":"驅魔師……？是那個穿全身乳膠裝的嗎？"},"stage":{"bg":"NOMAD_BORDER","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};